UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['Hydrography measures the bottom and features of water bodies and reduces them to a chart datum.','Single-beam gives a profile, multibeam gives full-coverage bathymetry, side-scan gives an acoustic image.','Every sounding needs a horizontal position, a measured depth, and a water-level correction to a datum.']::text[], learning_objectives=ARRAY['Define hydrographic surveying and state its principal purposes and deliverables.','Distinguish the major acoustic sensing methods: single-beam, multibeam, and side-scan sonar.','Explain how horizontal position and vertical depth are combined into a reduced sounding.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='cd6e08f5-2b80-471a-83f6-c8772f984e59';
DELETE FROM lesson_blocks WHERE lesson_id='cd6e08f5-2b80-471a-83f6-c8772f984e59';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Tidal datums are long-term averages of high/low waters over a 19-year epoch, not single observations.','MLLW is the usual chart (depth) datum; MHW/MHHW are the usual boundary datums.','MHHW averages only the higher daily high water and lies landward of MHW.']::text[], learning_objectives=ARRAY['Define the principal tidal datums: MLLW, MLW, MTL/MSL, MHW, and MHHW.','Explain tidal datum determination over the 18.6-year National Tidal Datum Epoch.','Compute tide range and relate observed water level to a chart datum.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='8efb96e2-80b3-4ac3-9ab6-2aaf48ad7a46';
DELETE FROM lesson_blocks WHERE lesson_id='8efb96e2-80b3-4ac3-9ab6-2aaf48ad7a46';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Reduced depth = raw sounding - tide height above datum.','RTK GNSS provides centimeter horizontal positions and can supply the vertical reference too.','Bathymetric models (surfaces, contours, TINs) are built from reduced, positioned soundings.']::text[], learning_objectives=ARRAY['Plan sounding lines and density for single-beam and multibeam bathymetric surveys.','Apply depth reduction: reduced depth = raw sounding - tide height relative to datum.','Position the vessel and soundings with RTK GNSS and account for transducer offsets.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='6ca85832-a702-4401-bd79-f70b989ddd1e';
DELETE FROM lesson_blocks WHERE lesson_id='6ca85832-a702-4401-bd79-f70b989ddd1e';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['A tidal coastal boundary is a tidal datum line surveyed on the ground, not a visible feature.','Texas is dual: MHHW for Spanish/Mexican grants, MHW for Texas-law grants (Luttes).','Gradual change moves the boundary (accretion/erosion); sudden avulsion fixes it.']::text[], learning_objectives=ARRAY['Identify the tidal datum that defines a coastal upland boundary.','Apply the Texas dual standard from Luttes v. State (MHHW vs. MHW) based on sovereign source.','Distinguish accretion, reliction, erosion, and avulsion and their effect on a coastal boundary.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='823b0a39-0438-4e0b-9544-e5782e6e7a8a';
DELETE FROM lesson_blocks WHERE lesson_id='823b0a39-0438-4e0b-9544-e5782e6e7a8a';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Texas defines a navigable stream by an average bed width of 30 feet ''from its mouth up.''','Navigable Texas streams have State-owned beds; the private boundary is the gradient boundary.','On non-navigable streams the abutting owner takes title to the center of the channel.']::text[], learning_objectives=ARRAY['Apply the Texas statutory 30-foot rule for navigable streams.','Locate the boundary of a navigable Texas stream using the gradient boundary method.','Distinguish riparian (stream) from littoral (sea/lake) situations and State bed ownership.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='52f79f9d-0221-4ca2-a4b0-8748463e791e';
DELETE FROM lesson_blocks WHERE lesson_id='52f79f9d-0221-4ca2-a4b0-8748463e791e';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['The Texas Open Beaches Act protects a public easement to the vegetation line on Gulf beaches.','Severance v. Patterson: the easement may roll with gradual change but not automatically after avulsion.','Coastal work intersects multiple agencies and permits (TCEQ, GLO, USACE, public-trust lands).']::text[], learning_objectives=ARRAY['Identify the public-beach easement and rolling-easement doctrine under the Texas Open Beaches Act.','Explain how Severance v. Patterson limited the rolling easement after avulsion.','List key regulatory players and permits affecting coastal and hydrographic work.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='7829ced8-18ca-452d-9a24-dcf687354ea7';
DELETE FROM lesson_blocks WHERE lesson_id='7829ced8-18ca-452d-9a24-dcf687354ea7';
  'eeee2150-0000-0000-0000-000000000001', 'Reduced depth from raw sounding and tide height', 'Reduced depth from raw sounding and tide height', 'Hydrographic Surveying - Depth Reduction', 'Sounding Reduction', 'numeric_input', 'easy', 'A draft-corrected raw sounding of {{raw:f2}} ft is recorded when the observed tide height is {{tide:f2}} ft above the chart datum. What is the reduced depth (ft) relative to the datum?', 'raw - tide', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"raw","type":"float","min":8,"max":40,"decimals":2},{"name":"tide","type":"float","min":0.5,"max":4,"decimals":2}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Reduction formula","formula":"reduced = raw - tide","calculation_template":"reduced = {{raw:f2}} - {{tide:f2}}"},{"step_number":2,"title":"Reduced depth","result_template":"{{raw:f2}} - {{tide:f2}} = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Subtracting the tide height above datum ({{tide:f2}} ft) from the raw sounding ({{raw:f2}} ft) refers the depth to the chart datum: {{_answer}} ft.', 'c1000015-0000-0000-0000-000000000015', ARRAY['buildout','module-21','practice']::text[], true, 'buildout:m21');
  'eeee2150-0000-0000-0000-000000000002', 'Mean tide range from MHW and MLW datums', 'Mean tide range from MHW and MLW datums', 'Hydrographic Surveying - Tidal Datums', 'Tide Range', 'numeric_input', 'easy', 'At a tide station the Mean High Water datum is {{mhw:f2}} ft and the Mean Low Water datum is {{mlw:f2}} ft above chart datum. What is the mean tide range (ft)?', 'mhw - mlw', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"mhw","type":"float","min":1.5,"max":6,"decimals":2},{"name":"drop","type":"float","min":0.8,"max":3,"decimals":2}]'::jsonb, '[{"name":"mlw","formula":"mhw - drop"}]'::jsonb, '[{"step_number":1,"title":"Range formula","formula":"range = MHW - MLW","calculation_template":"range = {{mhw:f2}} - {{mlw:f2}}"},{"step_number":2,"title":"Mean tide range","result_template":"{{mhw:f2}} - {{mlw:f2}} = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The mean tide range is the vertical difference between the MHW and MLW datums: {{mhw:f2}} - {{mlw:f2}} = {{_answer}} ft.', 'c1000015-0000-0000-0000-000000000015', ARRAY['buildout','module-21','practice']::text[], true, 'buildout:m21');
  'eeee2150-0000-0000-0000-000000000003', 'Area of accreted land along a frontage', 'Area of accreted land along a frontage', 'Hydrographic Surveying - Water Boundaries', 'Accretion', 'numeric_input', 'medium', 'A riparian tract has {{frontage:f1}} ft of water frontage. Over a period of years, gradual accretion adds an average width of {{accr:f1}} ft of new land along the entire frontage. What is the approximate area of accreted land (square feet)?', 'frontage * accr', '{"decimals":0,"unit":"sq ft","tolerance":1}', '[{"name":"frontage","type":"float","min":150,"max":900,"decimals":1},{"name":"accr","type":"float","min":5,"max":60,"decimals":1}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Area formula","formula":"area = frontage x average accretion width","calculation_template":"area = {{frontage:f1}} x {{accr:f1}}"},{"step_number":2,"title":"Accreted area","result_template":"{{frontage:f1}} x {{accr:f1}} = {{_answer}} sq ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Gradual accretion adds land to the upland owner. Treating the new land as a strip, area = frontage x average accretion width = {{frontage:f1}} x {{accr:f1}} = {{_answer}} sq ft.', 'c1000015-0000-0000-0000-000000000015', ARRAY['buildout','module-21','practice']::text[], true, 'buildout:m21');
COMMIT;
