INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0001-0000-0000-000000000000', 'cd6e08f5-2b80-471a-83f6-c8772f984e59', 'text', '{"html":"<h3>What hydrographic surveying is</h3><p><strong>Hydrographic surveying</strong> is the branch of surveying that measures and describes the physical features of water bodies and the land beneath them: depths, the shape of the bottom (<em>bathymetry</em>), the shoreline, tides and currents, and submerged hazards. Its classic purposes are <strong>safe navigation</strong> (nautical charts), <strong>engineering</strong> (dredging, channels, pipelines, bridge and dam siting), <strong>resource and environmental work</strong> (sediment volumes, habitat, scour), and <strong>boundary determination</strong> along water. Unlike a topographic survey on dry land, the surveyor cannot see or directly occupy the surface being mapped, so depths are sensed remotely from a moving vessel and the water surface itself is constantly changing height. A hydrographic survey therefore always couples three measurements at every point: a <strong>horizontal position</strong>, a <strong>measured depth</strong>, and a <strong>water-level (tide) observation</strong> used to reduce that depth to a fixed vertical datum. The reduced result is a depth referenced to a chart datum that anyone can re-use, regardless of the tide stage at the moment of measurement.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0001-0000-0000-000000000001', 'cd6e08f5-2b80-471a-83f6-c8772f984e59', 'text', '{"html":"<h3>Acoustic sensing methods</h3><p>Modern depths are measured acoustically with an <strong>echosounder</strong>, which times an acoustic pulse from the transducer to the bottom and back. Three sensor families dominate:</p><ul><li><strong>Single-beam echosounder (SBES):</strong> one narrow vertical beam giving a depth directly under the vessel. Cheap and simple, it yields a <em>profile</em> of soundings along the track line; coverage between lines is interpolated.</li><li><strong>Multibeam echosounder (MBES):</strong> a fan of many beams across-track, producing a dense swath of soundings on each pass and full-bottom coverage. It is the standard for charting, channel surveys, and volumetric work.</li><li><strong>Side-scan sonar (SSS):</strong> tows or mounts transducers that insonify the bottom obliquely to produce a photo-like <em>acoustic image</em>. Side-scan excels at finding objects (wrecks, debris, rock, pipelines) and characterizing bottom texture, but does not by itself give accurate depths.</li></ul><p>In practice a charting survey often pairs MBES for bathymetry with SSS for object detection, while a simple cross-section job may use only SBES.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0001-0000-0000-000000000002', 'cd6e08f5-2b80-471a-83f6-c8772f984e59', 'table', '{"headers":["Method","Coverage","Primary output","Typical use"],"rows":[["Single-beam (SBES)","Single nadir point","Depth profile along track","Cross-sections, reconnaissance, small jobs"],["Multibeam (MBES)","Across-track swath (full bottom)","Dense bathymetric surface","Charting, dredge/channel, volumes"],["Side-scan (SSS)","Two oblique image swaths","Acoustic image of bottom","Object/hazard detection, bottom type"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0001-0000-0000-000000000003', 'cd6e08f5-2b80-471a-83f6-c8772f984e59', 'equation', '{"latex":"d = \\frac{c \\, t}{2}","label":"Acoustic depth from two-way travel time (c = sound speed, t = travel time)","display":"block"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0001-0000-0000-000000000004', 'cd6e08f5-2b80-471a-83f6-c8772f984e59', 'callout', '{"type":"info","text":"Acoustic depths depend on the speed of sound in water (~1500 m/s), which varies with temperature, salinity, and pressure. A sound-velocity profile (SVP) is collected and applied so beams are ray-traced correctly; an uncorrected SVP biases outer multibeam beams the most."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0001-0000-0000-000000000005', 'cd6e08f5-2b80-471a-83f6-c8772f984e59', 'text', '{"html":"<h3>From raw echo to charted depth</h3><p>A raw sounding is only the distance from the transducer to the bottom at the instant of measurement. To be useful it must be <strong>reduced</strong>: corrected for the transducer draft (how deep the transducer sits below the waterline), for vessel motion (heave, roll, pitch from an inertial sensor), and most importantly for the <strong>stage of the tide</strong>. Because the water surface rises and falls, the same spot on the bottom would yield different raw depths at different times. By subtracting the observed height of the water surface above the chart datum, every sounding is referred to one common <strong>vertical datum</strong> (commonly Mean Lower Low Water for charts). The horizontal position of each sounding is fixed by GNSS, and the whole stream of position + depth + tide is time-tagged so the three can be merged. Lesson 2 covers tidal datums; Lesson 3 covers the survey methods and depth reduction in detail.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0001-0000-0000-000000000006', 'cd6e08f5-2b80-471a-83f6-c8772f984e59', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Coverage geometry of single-beam (point), multibeam (swath), and side-scan (oblique image) sensors."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0001-0000-0000-000000000007', 'cd6e08f5-2b80-471a-83f6-c8772f984e59', 'key_takeaways', '{"title":"Key Takeaways","items":["Hydrography maps depths, bottom shape, shoreline, and submerged hazards from a moving vessel.","SBES = profile; MBES = full-coverage swath; SSS = acoustic image for object detection.","Depth = (sound speed x travel time) / 2, then reduced for draft, motion, and tide.","Every charted sounding combines a GNSS position, a measured depth, and a water-level correction to a datum."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0002-0000-0000-000000000000', '8efb96e2-80b3-4ac3-9ab6-2aaf48ad7a46', 'text', '{"html":"<h3>Why tidal datums matter</h3><p>A <strong>tidal datum</strong> is a vertical reference plane defined by a long-term average of a particular phase of the tide. Because tides rise and fall continuously, a single water-level reading is useless as a reference; instead we average the same phase (e.g., every low water) over many years to get a stable plane. Two jobs depend on these datums. First, <strong>depth reduction</strong>: charted depths are referenced to a low-water datum so a mariner reading the chart sees a conservative (shallow) depth. Second, <strong>boundary determination</strong>: the legal edge of tidal water is defined by a high-water datum. Getting the datum wrong moves both the charted depth and the property line. The U.S. determines datums over the <strong>National Tidal Datum Epoch</strong>, a specific <strong>19-year</strong> period (~18.6 years is the lunar nodal cycle) chosen so that periodic astronomical variations average out.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0002-0000-0000-000000000001', '8efb96e2-80b3-4ac3-9ab6-2aaf48ad7a46', 'table', '{"headers":["Datum","Definition","Typical use"],"rows":[["MHHW","Mean Higher High Water - average of the higher of the two daily high waters","Coastal boundary (esp. Spanish/Mexican grants in TX)"],["MHW","Mean High Water - average of all high waters","Ordinary coastal boundary / shoreline"],["MTL / MSL","Mean Tide Level / Mean Sea Level - mean of MHW and MLW / mean of all levels","Reference, leveling tie"],["MLW","Mean Low Water - average of all low waters","Tide range, some boundaries"],["MLLW","Mean Lower Low Water - average of the lower of the two daily low waters","U.S. chart (sounding) datum"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0002-0000-0000-000000000002', '8efb96e2-80b3-4ac3-9ab6-2aaf48ad7a46', 'equation', '{"latex":"\\text{Tide range} = \\text{MHW} - \\text{MLW} \\qquad \\text{Great Diurnal Range} = \\text{MHHW} - \\text{MLLW}","label":"Tidal ranges from datums","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0002-0000-0000-000000000003', '8efb96e2-80b3-4ac3-9ab6-2aaf48ad7a46', 'text', '{"html":"<h3>Determining a datum at a site</h3><p>A first-order tide station observes water level continuously for the full 19-year epoch and averages each phase directly. Most survey sites cannot wait 19 years, so a temporary gauge is set and observed for a shorter span (often a month or more), then tied to a nearby <strong>control tide station</strong> with a known accepted epoch datum. By <strong>simultaneous comparison</strong> (the difference or amplitude-ratio method), the short series at the project gauge is corrected to the equivalent 19-year value. The accepted datums are then connected to land by leveling from the gauge zero to permanent <strong>tidal bench marks</strong>, so the water-level datum and the geodetic vertical datum (e.g., NAVD88) can be inter-related. This bench-mark tie is what lets a GNSS or leveled elevation be converted into a height above MLLW or MHW.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0002-0000-0000-000000000004', '8efb96e2-80b3-4ac3-9ab6-2aaf48ad7a46', 'callout', '{"type":"warning","text":"Texas differs: the coastal boundary datum depends on the sovereign source of the grant. Spanish/Mexican grants are bounded by MEAN HIGHER HIGH WATER (MHHW); Anglo-American (Republic/State of Texas) grants are bounded by MEAN HIGH TIDE / MEAN HIGH WATER (MHW). Luttes v. State, 159 Tex. 500, 324 S.W.2d 167 (1959)."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0002-0000-0000-000000000005', '8efb96e2-80b3-4ac3-9ab6-2aaf48ad7a46', 'text', '{"html":"<h3>Reducing an observed level to a datum</h3><p>During a survey the gauge records the instantaneous water surface. To reduce a sounding, the surveyor needs the height of that surface <em>above the chart datum</em> at the moment each depth was measured. If the gauge zero is set on the chart datum, the recorded staff reading is exactly the tide height to subtract from the raw sounding. If the gauge zero is offset, the known offset is applied. Smoothly varying corrections (interpolated between high and low waters, or modeled) avoid step changes between soundings. The same reduced framework supports computing range statistics: for example, with MHW = 1.8 ft and MLW = 0.2 ft above datum, the mean tide range is 1.6 ft. These relationships are the basis for the lesson''s tide-range and depth-reduction problems.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0002-0000-0000-000000000006', '8efb96e2-80b3-4ac3-9ab6-2aaf48ad7a46', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Tidal datum ladder (MLLW, MLW, MTL, MHW, MHHW) with mean and diurnal ranges."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0002-0000-0000-000000000007', '8efb96e2-80b3-4ac3-9ab6-2aaf48ad7a46', 'key_takeaways', '{"title":"Key Takeaways","items":["Datums are 19-year (National Tidal Datum Epoch) averages of a tide phase, not single readings.","MLLW is the U.S. chart datum; MHW and MHHW are the usual boundary datums.","Short observations are corrected to the epoch by simultaneous comparison with a control station.","Tide range = MHW - MLW; great diurnal range = MHHW - MLLW.","Texas: MHHW for Spanish/Mexican grants, MHW for Texas-law grants (Luttes)."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0003-0000-0000-000000000000', '6ca85832-a702-4401-bd79-f70b989ddd1e', 'text', '{"html":"<h3>Planning the survey</h3><p>A bathymetric survey produces a model of the bottom from many positioned, reduced soundings. Planning starts with <strong>line layout</strong>. For single-beam work, parallel <strong>sounding lines</strong> are run at a spacing set by the required detail (e.g., 25-100 ft for engineering surveys), with perpendicular <strong>check lines</strong> (cross lines) to test consistency where they intersect main lines. For multibeam, line spacing is set so adjacent <strong>swaths overlap</strong> (commonly ~25-50% in deeper water) to guarantee full coverage and to compare overlap. The surveyor also fixes the <strong>vertical control</strong> (which tidal or geodetic datum), the <strong>sound-velocity</strong> strategy, and the <strong>positioning</strong> method before going afloat. Good geometry plus controlled speed keeps sounding density uniform and avoids gaps.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0003-0000-0000-000000000001', '6ca85832-a702-4401-bd79-f70b989ddd1e', 'text', '{"html":"<h3>Positioning the vessel with RTK GNSS</h3><p>Each sounding needs an accurate horizontal position the instant the depth is sensed. The modern standard is <strong>Real-Time Kinematic (RTK) GNSS</strong>: a base receiver on a known control point (or an RTN/VRS network) broadcasts corrections to the vessel rover, giving centimeter-level horizontal positions in real time. The GNSS antenna, the echosounder transducer, and the motion sensor are rarely at the same point, so the surveyor measures the <strong>lever-arm offsets</strong> between them and applies them, together with the vessel''s heading and attitude (heave, roll, pitch), so each sounding is referred to the actual transducer location and projected to the bottom correctly. <strong>RTK tide</strong> (ellipsoidally referenced surveying) can even replace a physical tide gauge: the RTK-derived antenna height, minus a geoid/separation model, yields the water-surface height relative to the chart datum directly.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0003-0000-0000-000000000002', '6ca85832-a702-4401-bd79-f70b989ddd1e', 'equation', '{"latex":"d_{reduced} = d_{raw} - h_{tide}","label":"Depth reduction: reduced depth = raw sounding - tide height above datum","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0003-0000-0000-000000000003', '6ca85832-a702-4401-bd79-f70b989ddd1e', 'callout', '{"type":"info","text":"Sign convention: depths are positive downward and tide height is positive above the chart datum. When the water is HIGH (large positive tide height) the raw echo is larger, so subtracting the tide height brings every sounding back to the same datum. A negative tide (below datum) increases the reduced depth."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0003-0000-0000-000000000004', '6ca85832-a702-4401-bd79-f70b989ddd1e', 'table', '{"headers":["Quantity","Symbol","Example value"],"rows":[["Raw sounding (transducer to bottom, draft-corrected)","d_raw","14.20 ft"],["Observed tide height above chart datum","h_tide","2.30 ft"],["Reduced depth (relative to datum)","d_reduced","11.90 ft"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0003-0000-0000-000000000005', '6ca85832-a702-4401-bd79-f70b989ddd1e', 'text', '{"html":"<h3>From soundings to a bathymetric map</h3><p>Once every sounding has a horizontal position and a reduced depth, the data are <strong>cleaned</strong> (spikes and noise removed), checked against the cross lines, and gridded into a bottom <strong>surface</strong>. From that surface the deliverables follow: <strong>depth contours</strong>, color-shaded relief, a TIN or DEM, cross-sections, and <strong>volumes</strong> (e.g., dredge cut/fill between a survey and a design grade). Quality is judged by agreement at main-line/cross-line intersections and by adherence to standards such as IHO survey orders. Because the map is only as good as the datum and positioning behind it, the surveyor documents the chart datum, the GNSS/RTK setup, sound-velocity handling, and the reduction applied so the bathymetry can be trusted and re-used.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0003-0000-0000-000000000006', '6ca85832-a702-4401-bd79-f70b989ddd1e', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Sounding-line plan with main lines and perpendicular cross (check) lines."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0003-0000-0000-000000000007', '6ca85832-a702-4401-bd79-f70b989ddd1e', 'key_takeaways', '{"title":"Key Takeaways","items":["Plan line spacing and cross lines (single-beam) or swath overlap (multibeam) for full, checkable coverage.","RTK GNSS gives centimeter horizontal positions; lever-arm offsets tie GNSS, transducer, and motion sensor.","Reduced depth = raw sounding - tide height above datum.","Reduced, positioned soundings are gridded into surfaces, contours, and volumes; cross lines verify quality."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0004-0000-0000-000000000000', '823b0a39-0438-4e0b-9544-e5782e6e7a8a', 'text', '{"html":"<h3>The boundary is a datum, not a line you can see</h3><p>Along tidal water the upland (private) boundary is the intersection of a defined <strong>tidal datum plane</strong> with the sloping shore. The general American rule (<em>Borax Consolidated v. City of Los Angeles</em>, 296 U.S. 10 (1935)) places that line at <strong>Mean High Water (MHW)</strong> - the average of all high waters over the 19-year epoch. To survey it, you do not chase a wet/dry line on the sand; you establish the MHW elevation from a tide station, then locate where that elevation meets the beach profile (by leveling or RTK), tracing the contour landward and seaward along the shore. The result is reproducible because it is tied to an averaged datum, not to today''s waterline.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0004-0000-0000-000000000001', '823b0a39-0438-4e0b-9544-e5782e6e7a8a', 'callout', '{"type":"warning","text":"Texas differs - the dual standard. The coastal datum depends on the original SOVEREIGN: Spanish/Mexican grants are bounded by MEAN HIGHER HIGH WATER (MHHW); Anglo-American (Republic/State of Texas) grants are bounded by MEAN HIGH TIDE / MEAN HIGH WATER (MHW). Luttes v. State, 159 Tex. 500, 324 S.W.2d 167 (1959). A coastal surveyor must establish the chain of title back to the original sovereign BEFORE choosing the datum."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0004-0000-0000-000000000002', '823b0a39-0438-4e0b-9544-e5782e6e7a8a', 'text', '{"html":"<h3>Why Texas is different: Luttes v. State</h3><p><em>Luttes v. State</em> (1959) concerned the 1829 Mexican \"Potrero de Buena Vista\" grant on the Laguna Madre. The Texas Supreme Court held that the seaward boundary of a <strong>Spanish or Mexican</strong> grant is the <strong>mean higher high water</strong> line, because the civil law in force when those grants issued defined the \"shore\" by the reach of the <em>highest</em> (winter) tides, which the Court translated into the surveyable MHHW datum. Grants made under <strong>Anglo-American law</strong> (after Texas''s own sovereignty) take the ordinary <strong>mean high tide / MHW</strong> line. Because MHHW averages only the higher of each day''s two high waters, the MHHW line sits <strong>landward</strong> of the MHW line - so the State''s seabed is larger under a Spanish/Mexican grant. The practical consequence: identical-looking coastal tracts can have boundaries at different elevations purely because of their sovereign origin.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0004-0000-0000-000000000003', '823b0a39-0438-4e0b-9544-e5782e6e7a8a', 'text', '{"html":"<h3>Movable boundaries: accretion, reliction, erosion, avulsion</h3><p>Water boundaries move with the water - but only when the change is gradual. <strong>Accretion</strong> (slow build-up of alluvion) and <strong>reliction</strong> (slow uncovering as water recedes) move the boundary outward and the upland owner <em>gains</em> land. <strong>Erosion</strong> (gradual loss) moves it landward and the owner <em>loses</em> land. <strong>Avulsion</strong> - a sudden, perceptible change such as a hurricane or a flood cutting a new channel - is different: the boundary is <strong>FIXED</strong> at its former location and does <em>not</em> follow the new waterline. Title does not shift merely because the water suddenly jumped. This gradual-moves / avulsive-fixes framework is mainstream American law and Texas follows it; the Texas twist appears in beach-easement law (next lesson) and in that the line being measured on streams is the gradient boundary rather than a simple high-water mark.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0004-0000-0000-000000000004', '823b0a39-0438-4e0b-9544-e5782e6e7a8a', 'table', '{"headers":["Process","Nature","Effect on boundary","Effect on owner"],"rows":[["Accretion","Gradual deposit of soil","Moves outward (follows water)","Gains land"],["Reliction","Gradual recession of water","Moves outward (follows water)","Gains land"],["Erosion","Gradual loss of soil","Moves landward (follows water)","Loses land"],["Avulsion","Sudden, perceptible change","FIXED at former location","No change of title"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0004-0000-0000-000000000005', '823b0a39-0438-4e0b-9544-e5782e6e7a8a', 'accordion', '{"sections":[{"title":"Case: Luttes v. State (1959)","content":"<p>Seaward boundary of an 1829 Mexican grant on the Laguna Madre is <strong>mean higher high water</strong>, distinguished from the <strong>mean high tide</strong> line used for grants under Anglo-American (Texas) law. The controlling Texas authority on coastal upland boundaries; requires the surveyor to identify the sovereign source first.</p>","open":false},{"title":"Contrast: Borax Consol. v. City of Los Angeles (1935)","content":"<p>The general U.S. rule fixes the ordinary tidal boundary at <strong>mean high water</strong> (average of all high waters over the epoch). Texas applies this only to its own-law grants; it adds the landward MHHW line for civil-law (Spanish/Mexican) grants.</p>","open":false}]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0004-0000-0000-000000000006', '823b0a39-0438-4e0b-9544-e5782e6e7a8a', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: On a sloping shore the MHHW datum line lies landward of the MHW line."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0004-0000-0000-000000000007', '823b0a39-0438-4e0b-9544-e5782e6e7a8a', 'key_takeaways', '{"title":"Key Takeaways","items":["Survey a tidal boundary by establishing the datum elevation and locating its intersection with the shore profile.","General rule = MHW (Borax). Texas dual rule: MHHW for Spanish/Mexican grants, MHW for Texas grants (Luttes).","MHHW lies landward of MHW, enlarging the State''s seabed for civil-law grants.","Accretion/reliction and erosion move the boundary; avulsion fixes it at its former location."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0005-0000-0000-000000000000', '52f79f9d-0221-4ca2-a4b0-8748463e791e', 'text', '{"html":"<h3>Riparian vs. littoral, and why navigability matters</h3><p>Owners along flowing water (a river or stream) hold <strong>riparian</strong> rights; owners along a sea or lake hold <strong>littoral</strong> rights. For a stream, the controlling question for the boundary and for who owns the bed is whether the stream is <strong>navigable</strong>. If it is navigable, the State of Texas owns the bed in trust for the public and the private patent stops at the stream boundary; if it is non-navigable, the abutting owner takes title to the <strong>center</strong> of the channel. So before running a riparian survey, the surveyor must decide navigability under Texas''s tests, then locate the correct boundary line.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0005-0000-0000-000000000001', '52f79f9d-0221-4ca2-a4b0-8748463e791e', 'callout', '{"type":"warning","text":"Texas differs - the 30-foot rule. A Texas stream is navigable-in-fact if it ''retains an average width of 30 feet from its mouth up.'' The 30 feet is measured across the ENTIRE BED (bank to bank), not the water flowing on a given day - so a sometimes-dry channel can still be navigable, with a State-owned bed. Tex. Nat. Res. Code Sec. 21.001(3). Texas also recognizes navigability-in-law for streams actually usable for public passage."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0005-0000-0000-000000000002', '52f79f9d-0221-4ca2-a4b0-8748463e791e', 'text', '{"html":"<h3>The Texas gradient boundary method</h3><p>For a navigable Texas stream the line between State-owned bed and private upland is the <strong>gradient boundary</strong> - a distinctively Texas construction, not the ordinary high-water mark used in most states. Following <em>Motl v. Boyd</em> (1926) and <em>Oklahoma v. Texas</em> (1923), the method locates a \"water-washed and relatively permanent\" line on the <strong>cut bank</strong> and constructs the boundary along the <strong>gradient of the flowing water midway between the lower level of the grass on the bank and the lower level of the bed</strong> at its average and mean stage during a year - disregarding extreme freshets and droughts. The bed is the soil \"alternately covered and left bare\" as the water reaches its average and mean stage. Surveyor A.A. Stiles developed the computation for the Red River line. In practice the surveyor levels the bank profile, identifies the qualifying water-washed feature, and computes the gradient line - a more involved procedure than reading a single high-water mark.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0005-0000-0000-000000000003', '52f79f9d-0221-4ca2-a4b0-8748463e791e', 'accordion', '{"sections":[{"title":"Case: Motl v. Boyd (1926)","content":"<p>Texas Supreme Court adopted the gradient boundary between public and private ownership along navigable streams and defined the \"bed\" as the soil alternately covered and left bare, adequate to contain the water at its average and mean stage during an entire year, without reference to extreme freshets or droughts.</p>","open":false},{"title":"Case: Oklahoma v. Texas (1923)","content":"<p>The U.S. Supreme Court adopted the gradient boundary for the Texas-Oklahoma line on the Red River. Its commissioner-surveyor A.A. Stiles developed the gradient boundary method (''water washed and relatively permanent elevation ... at the outer line of the river bed'').</p>","open":false},{"title":"State ownership of the bed","content":"<p>The State of Texas owns the beds of navigable streams in trust for the public. Private patents abutting a navigable stream run only to the gradient boundary; the bed below is sovereign land (subject to the Small Bill''s partial relinquishment of the bed surface, but not minerals).</p>","open":false}]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0005-0000-0000-000000000004', '52f79f9d-0221-4ca2-a4b0-8748463e791e', 'callout', '{"type":"warning","text":"Texas differs - surface water is State-owned. Owning the streambank does NOT give a right to use the water beyond limited domestic and livestock use; appropriative use requires a State permit administered by TCEQ on a prior-appropriation basis. Tex. Water Code Ch. 11 (Sec. 11.021). Recognized riparian claims were merged into the permit system by the Water Rights Adjudication Act of 1967."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0005-0000-0000-000000000005', '52f79f9d-0221-4ca2-a4b0-8748463e791e', 'table', '{"headers":["Situation","Bed ownership","Private boundary"],"rows":[["Navigable stream (avg. bed >= 30 ft)","State of Texas (in trust)","Gradient boundary"],["Non-navigable stream","Abutting owner","Center (thread) of channel"],["Tidal sea/bay (littoral)","State below the tidal datum","MHW or MHHW (Luttes)"]]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0005-0000-0000-000000000006', '52f79f9d-0221-4ca2-a4b0-8748463e791e', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Gradient boundary constructed on the cut bank of a navigable Texas stream."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0005-0000-0000-000000000007', '52f79f9d-0221-4ca2-a4b0-8748463e791e', 'key_takeaways', '{"title":"Key Takeaways","items":["Riparian = streams; littoral = sea/lake. Navigability controls bed ownership and the boundary.","Texas 30-foot rule: average bed width of 30 ft from its mouth up makes a stream navigable (entire bed, not the water).","Navigable stream boundary = gradient boundary (Motl v. Boyd, Oklahoma v. Texas); State owns the bed.","Non-navigable stream = owner takes to the center; Texas surface water is State-owned (use needs a permit)."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0006-0000-0000-000000000000', '7829ced8-18ca-452d-9a24-dcf687354ea7', 'text', '{"html":"<h3>The public beach and the Open Beaches Act</h3><p>Texas law strongly protects public access to Gulf beaches. Under the <strong>Texas Open Beaches Act (TOBA)</strong>, the public holds an easement over the <strong>dry beach</strong>, generally landward to the <strong>line of vegetation</strong>. Because shorelines move, that easement is treated as a <strong>rolling easement</strong> - as the beach naturally shifts, the public easement can migrate with it, so the boundary of public access is dynamic rather than a fixed survey line. For a coastal surveyor this means the relevant lines (the tidal boundary seaward and the vegetation line landward) are subject to change, and the work product should document the date and method of any shoreline location.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0006-0000-0000-000000000001', '7829ced8-18ca-452d-9a24-dcf687354ea7', 'callout', '{"type":"warning","text":"Texas differs - Severance v. Patterson, 370 S.W.3d 705 (Tex. 2012). The public beach easement may GRADUALLY migrate with naturally shifting beaches, but it does NOT automatically ''roll'' onto previously private dry land after an AVULSIVE event (e.g., a hurricane suddenly moving the vegetation line landward). After avulsion, the State must establish a NEW easement rather than rely on the prior one rolling inland."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0006-0000-0000-000000000002', '7829ced8-18ca-452d-9a24-dcf687354ea7', 'text', '{"html":"<h3>Why the avulsion distinction matters</h3><p><em>Severance v. Patterson</em> imported the classic accretion/avulsion boundary principle into beach-access law. The result is a <strong>gradual / avulsive distinction applied to the easement itself</strong>: <strong>gradual</strong> shoreline change lets the public easement <em>roll</em> inland, but a <strong>sudden, avulsive</strong> change (a hurricane shifting the vegetation line) <em>fixes</em> the easement rather than rolling it onto land that was private before the event. This mirrors the rule that gradual processes move a water boundary while avulsion fixes it. For the surveyor, it means a single storm can change whether a strip of land is burdened by the public easement, and re-establishing the line after a major event may require a new legal determination rather than simply re-running the prior easement landward.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0006-0000-0000-000000000003', '7829ced8-18ca-452d-9a24-dcf687354ea7', 'text', '{"html":"<h3>Regulatory players and permits</h3><p>Coastal and hydrographic projects touch several jurisdictions at once. <strong>Surface water</strong> (every river, stream, bay, and arm of the Gulf) is <strong>State-owned</strong>; appropriative use requires a permit from the <strong>Texas Commission on Environmental Quality (TCEQ)</strong> under the prior-appropriation system (Tex. Water Code Ch. 11). The <strong>Texas General Land Office (GLO)</strong> manages State-owned submerged lands and coastal public-trust lands and holds the original grant records a coastal boundary survey must trace. Federal work in navigable waters and wetlands typically involves the <strong>U.S. Army Corps of Engineers</strong> (Clean Water Act Sec. 404 / Rivers and Harbors Act permits) and may require environmental review. Dredging, beachfront construction, and shoreline alteration commonly need multiple approvals. The surveyor''s role is to deliver defensible boundary and bathymetric data - tied to the correct datum and the correct sovereign chain of title - on which these permitting and ownership decisions rest.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0006-0000-0000-000000000004', '7829ced8-18ca-452d-9a24-dcf687354ea7', 'table', '{"headers":["Entity / law","Role in coastal & hydrographic work"],"rows":[["TCEQ (Tex. Water Code Ch. 11)","Permits appropriative use of State-owned surface water (prior appropriation)"],["Texas General Land Office (GLO)","Manages State submerged/public-trust lands; custodian of original grant records"],["Texas Open Beaches Act / Severance","Public beach easement to the vegetation line; rolls gradually, not after avulsion"],["U.S. Army Corps of Engineers","Federal permits for work in navigable waters and wetlands (Sec. 404 / RHA)"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0006-0000-0000-000000000005', '7829ced8-18ca-452d-9a24-dcf687354ea7', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Public beach easement between the tidal boundary and the line of vegetation under TOBA."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2110-0006-0000-0000-000000000006', '7829ced8-18ca-452d-9a24-dcf687354ea7', 'key_takeaways', '{"title":"Key Takeaways","items":["TOBA gives the public a rolling easement over the dry beach to the line of vegetation.","Severance v. Patterson (2012): the easement rolls with gradual change but not automatically after avulsion.","Texas surface water is State-owned; appropriative use needs a TCEQ permit (prior appropriation).","Coastal work also engages the GLO (public-trust lands, grant records) and USACE (federal navigable-waters permits)."]}'::jsonb, 6);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2140-0000-0000-0000-000000000001', 'Hydrographic survey', 'A survey that measures depths, bottom configuration (bathymetry), shoreline, tides/currents, and submerged hazards of a water body, reduced to a chart datum.', 'Mapping below the water surface.', 'c1000015-0000-0000-0000-000000000015', 'cd6e08f5-2b80-471a-83f6-c8772f984e59', 'surveying', ARRAY['buildout','module-21']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2140-0000-0000-0000-000000000002', 'Echosounder', 'An instrument that measures depth by timing an acoustic pulse from a transducer to the bottom and back; depth = (sound speed x two-way travel time) / 2.', 'Sonar for depth.', 'c1000015-0000-0000-0000-000000000015', 'cd6e08f5-2b80-471a-83f6-c8772f984e59', 'surveying', ARRAY['buildout','module-21']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2140-0000-0000-0000-000000000003', 'Multibeam echosounder (MBES)', 'An echosounder that emits a fan of beams across-track to produce a continuous swath of soundings, giving full-bottom coverage in one pass.', 'A fan, not a point.', 'c1000015-0000-0000-0000-000000000015', 'cd6e08f5-2b80-471a-83f6-c8772f984e59', 'surveying', ARRAY['buildout','module-21']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2140-0000-0000-0000-000000000004', 'Side-scan sonar (SSS)', 'A sonar that insonifies the bottom obliquely to produce a photo-like acoustic image, used to detect objects and characterize bottom texture; it does not give accurate depths by itself.', 'Image, not depth.', 'c1000015-0000-0000-0000-000000000015', 'cd6e08f5-2b80-471a-83f6-c8772f984e59', 'surveying', ARRAY['buildout','module-21']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2140-0000-0000-0000-000000000005', 'Mean Lower Low Water (MLLW)', 'The average height of the lower of the two daily low waters over the National Tidal Datum Epoch; the standard chart (sounding) datum in the United States.', 'U.S. depth datum.', 'c1000015-0000-0000-0000-000000000015', '8efb96e2-80b3-4ac3-9ab6-2aaf48ad7a46', 'surveying', ARRAY['buildout','module-21']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2140-0000-0000-0000-000000000006', 'Mean Higher High Water (MHHW)', 'The average of the higher of the two daily high waters over the epoch; lies landward of MHW and is the Texas boundary datum for Spanish/Mexican grants.', 'Averages only the higher high.', 'c1000015-0000-0000-0000-000000000015', '8efb96e2-80b3-4ac3-9ab6-2aaf48ad7a46', 'surveying', ARRAY['buildout','module-21']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2140-0000-0000-0000-000000000007', 'National Tidal Datum Epoch', 'A specific 19-year period (capturing the ~18.6-year lunar nodal cycle) over which tidal datums are averaged so astronomical variations cancel out.', '19 years.', 'c1000015-0000-0000-0000-000000000015', '8efb96e2-80b3-4ac3-9ab6-2aaf48ad7a46', 'surveying', ARRAY['buildout','module-21']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2140-0000-0000-0000-000000000008', 'Mean tide range', 'The vertical difference between Mean High Water and Mean Low Water (MHW - MLW).', 'High datum minus low datum.', 'c1000015-0000-0000-0000-000000000015', '8efb96e2-80b3-4ac3-9ab6-2aaf48ad7a46', 'surveying', ARRAY['buildout','module-21']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2140-0000-0000-0000-000000000009', 'Reduced depth (depth reduction)', 'The raw, draft-corrected sounding minus the observed tide height above the chart datum, giving a depth referenced to that fixed datum.', 'Subtract the tide.', 'c1000015-0000-0000-0000-000000000015', '6ca85832-a702-4401-bd79-f70b989ddd1e', 'surveying', ARRAY['buildout','module-21']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2140-0000-0000-0000-000000000010', 'RTK GNSS', 'Real-Time Kinematic GNSS: a base/rover (or network) setup providing centimeter-level real-time positions used to position the survey vessel and each sounding.', 'Centimeter real-time positioning.', 'c1000015-0000-0000-0000-000000000015', '6ca85832-a702-4401-bd79-f70b989ddd1e', 'surveying', ARRAY['buildout','module-21']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2140-0000-0000-0000-000000000011', 'Cross (check) line', 'A sounding line run perpendicular to the main lines so that depth agreement at the intersections can be used to assess survey quality.', 'Crosses the main lines for QC.', 'c1000015-0000-0000-0000-000000000015', '6ca85832-a702-4401-bd79-f70b989ddd1e', 'surveying', ARRAY['buildout','module-21']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2140-0000-0000-0000-000000000012', 'Lever-arm offset', 'The measured 3-D vector between the GNSS antenna, the transducer, and the motion sensor, applied so soundings refer to the true transducer location.', 'Sensors are not co-located.', 'c1000015-0000-0000-0000-000000000015', '6ca85832-a702-4401-bd79-f70b989ddd1e', 'surveying', ARRAY['buildout','module-21']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2140-0000-0000-0000-000000000013', 'Luttes v. State (1959)', 'Texas Supreme Court case holding that Spanish/Mexican coastal grants are bounded by mean higher high water (MHHW), while Anglo-American/Texas grants take the mean high tide (MHW) line.', 'Two datums by sovereign source.', 'c1000015-0000-0000-0000-000000000015', '823b0a39-0438-4e0b-9544-e5782e6e7a8a', 'surveying', ARRAY['buildout','module-21']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2140-0000-0000-0000-000000000014', 'Accretion', 'The gradual, imperceptible deposit of soil (alluvion) along a water boundary; the boundary moves with the water and the upland owner gains the new land.', 'Slow gain.', 'c1000015-0000-0000-0000-000000000015', '823b0a39-0438-4e0b-9544-e5782e6e7a8a', 'surveying', ARRAY['buildout','module-21']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2140-0000-0000-0000-000000000015', 'Avulsion', 'A sudden, perceptible change in a watercourse or shoreline (e.g., hurricane, channel cut); the boundary is fixed at its former location and title does not follow the water.', 'Sudden = boundary frozen.', 'c1000015-0000-0000-0000-000000000015', '823b0a39-0438-4e0b-9544-e5782e6e7a8a', 'surveying', ARRAY['buildout','module-21']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2140-0000-0000-0000-000000000016', 'Mean high water (MHW) boundary', 'The ordinary tidal upland boundary (Borax, 1935) at the average of all high waters; the datum used in Texas for grants made under Anglo-American/Texas law.', 'Average of all highs.', 'c1000015-0000-0000-0000-000000000015', '823b0a39-0438-4e0b-9544-e5782e6e7a8a', 'surveying', ARRAY['buildout','module-21']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2140-0000-0000-0000-000000000017', '30-foot rule (Texas navigable stream)', 'Texas statutory test: a stream is navigable if it retains an average bed width of 30 feet from its mouth up, measured across the entire bed (Tex. Nat. Res. Code Sec. 21.001(3)).', 'Average bed width.', 'c1000015-0000-0000-0000-000000000015', '52f79f9d-0221-4ca2-a4b0-8748463e791e', 'surveying', ARRAY['buildout','module-21']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2140-0000-0000-0000-000000000018', 'Gradient boundary', 'The distinctively Texas line between State-owned bed and private upland on a navigable stream, constructed along the gradient of the cut bank at the water''s average and mean stage (Motl v. Boyd).', 'Not the ordinary high-water mark.', 'c1000015-0000-0000-0000-000000000015', '52f79f9d-0221-4ca2-a4b0-8748463e791e', 'surveying', ARRAY['buildout','module-21']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2140-0000-0000-0000-000000000019', 'Riparian vs. littoral', 'Riparian rights belong to owners along flowing watercourses (rivers/streams); littoral rights belong to owners along seas, bays, or lakes.', 'Stream vs. sea/lake.', 'c1000015-0000-0000-0000-000000000015', '52f79f9d-0221-4ca2-a4b0-8748463e791e', 'surveying', ARRAY['buildout','module-21']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2140-0000-0000-0000-000000000020', 'State ownership of navigable stream beds', 'Texas owns the beds of navigable streams in trust for the public; abutting patents run only to the gradient boundary, with the bed below remaining sovereign land.', 'Public bed below the gradient line.', 'c1000015-0000-0000-0000-000000000015', '52f79f9d-0221-4ca2-a4b0-8748463e791e', 'surveying', ARRAY['buildout','module-21']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2140-0000-0000-0000-000000000021', 'Texas Open Beaches Act (TOBA)', 'Texas statute protecting a public easement over the dry beach, generally landward to the line of vegetation, on Gulf beaches.', 'Public access to the dry beach.', 'c1000015-0000-0000-0000-000000000015', '7829ced8-18ca-452d-9a24-dcf687354ea7', 'surveying', ARRAY['buildout','module-21']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2140-0000-0000-0000-000000000022', 'Rolling easement', 'The doctrine that the public beach easement migrates with a naturally shifting beach, so the access boundary is dynamic rather than a fixed survey line.', 'It moves with the beach.', 'c1000015-0000-0000-0000-000000000015', '7829ced8-18ca-452d-9a24-dcf687354ea7', 'surveying', ARRAY['buildout','module-21']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2140-0000-0000-0000-000000000023', 'Severance v. Patterson (2012)', 'Texas Supreme Court case holding the public beach easement may migrate with gradual change but does not automatically roll onto previously private land after an avulsive event.', 'Gradual rolls; avulsion fixes.', 'c1000015-0000-0000-0000-000000000015', '7829ced8-18ca-452d-9a24-dcf687354ea7', 'surveying', ARRAY['buildout','module-21']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2140-0000-0000-0000-000000000024', 'TCEQ surface-water permit', 'Authorization from the Texas Commission on Environmental Quality to appropriate State-owned surface water under the prior-appropriation system (Tex. Water Code Ch. 11).', 'State owns the water; permit to use it.', 'c1000015-0000-0000-0000-000000000015', '7829ced8-18ca-452d-9a24-dcf687354ea7', 'surveying', ARRAY['buildout','module-21']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2130-0000-0000-0000-000000000001', 'Which sensor produces a full-coverage swath of soundings across-track in a single pass?', 'multiple_choice', '["Single-beam echosounder","Multibeam echosounder","Side-scan sonar","Lead line"]'::jsonb, 'Multibeam echosounder', 'A multibeam echosounder emits a fan of beams across-track, giving full-bottom coverage per pass. Single-beam yields only a nadir profile; side-scan produces an image, not accurate depths; a lead line is a single manual depth.', 'easy', 'c1000015-0000-0000-0000-000000000015', 'cd6e08f5-2b80-471a-83f6-c8772f984e59', ARRAY['buildout','module-21']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2130-0000-0000-0000-000000000002', 'Side-scan sonar is primarily used to obtain accurate water depths.', 'true_false', '["True","False"]'::jsonb, 'False', 'Side-scan produces a photo-like acoustic image used to detect objects and characterize the bottom; it does not by itself yield accurate depths. Depths come from echosounders.', 'easy', 'c1000015-0000-0000-0000-000000000015', 'cd6e08f5-2b80-471a-83f6-c8772f984e59', ARRAY['buildout','module-21']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2130-0000-0000-0000-000000000003', 'An echosounder measures a two-way acoustic travel time of 0.020 s in water where the speed of sound is 1500 m/s. What is the depth?', 'multiple_choice', '["7.5 m","15 m","30 m","150 m"]'::jsonb, '15 m', 'Depth = (c x t)/2 = (1500 x 0.020)/2 = 30/2 = 15 m. The division by two accounts for the down-and-back path.', 'medium', 'c1000015-0000-0000-0000-000000000015', 'cd6e08f5-2b80-471a-83f6-c8772f984e59', ARRAY['buildout','module-21']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2130-0000-0000-0000-000000000004', 'What is the standard chart (sounding) datum for U.S. nautical charts?', 'multiple_choice', '["Mean High Water (MHW)","Mean Sea Level (MSL)","Mean Lower Low Water (MLLW)","Mean Higher High Water (MHHW)"]'::jsonb, 'Mean Lower Low Water (MLLW)', 'U.S. charts reference depths to MLLW, a conservative low-water datum so mariners see shallow (safe) depths. MHW/MHHW are high-water boundary datums; MSL is a mid-level reference.', 'easy', 'c1000015-0000-0000-0000-000000000015', '8efb96e2-80b3-4ac3-9ab6-2aaf48ad7a46', ARRAY['buildout','module-21']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2130-0000-0000-0000-000000000005', 'The National Tidal Datum Epoch is a single high-water observation used to set datums.', 'true_false', '["True","False"]'::jsonb, 'False', 'The epoch is a specific 19-year period over which a tide phase is averaged, capturing the ~18.6-year lunar nodal cycle so astronomical variations cancel out. It is not a single observation.', 'easy', 'c1000015-0000-0000-0000-000000000015', '8efb96e2-80b3-4ac3-9ab6-2aaf48ad7a46', ARRAY['buildout','module-21']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2130-0000-0000-0000-000000000006', 'At a station MHW = 1.9 ft and MLW = 0.3 ft above chart datum. What is the mean tide range?', 'numeric_input', '[]'::jsonb, '1.6', 'Mean tide range = MHW - MLW = 1.9 - 0.3 = 1.6 ft.', 'easy', 'c1000015-0000-0000-0000-000000000015', '8efb96e2-80b3-4ac3-9ab6-2aaf48ad7a46', ARRAY['buildout','module-21']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2130-0000-0000-0000-000000000007', 'How is a short tide-gauge record at a project site corrected to the full 19-year datum?', 'multiple_choice', '["By averaging only the project gauge readings","By simultaneous comparison with a nearby control tide station of known epoch datum","By assuming MSL equals MLLW","By using a single spring-tide observation"]'::jsonb, 'By simultaneous comparison with a nearby control tide station of known epoch datum', 'Short series are reduced to the 19-year equivalent by simultaneous comparison (difference/ratio) with a control station whose accepted epoch datums are known. Short-record averages alone are not epoch datums.', 'medium', 'c1000015-0000-0000-0000-000000000015', '8efb96e2-80b3-4ac3-9ab6-2aaf48ad7a46', ARRAY['buildout','module-21']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2130-0000-0000-0000-000000000008', 'A raw, draft-corrected sounding is 16.40 ft when the observed tide height is 2.70 ft above chart datum. What is the reduced depth?', 'numeric_input', '[]'::jsonb, '13.7', 'Reduced depth = raw sounding - tide height = 16.40 - 2.70 = 13.70 ft. Subtracting the tide refers the depth to the chart datum.', 'medium', 'c1000015-0000-0000-0000-000000000015', '6ca85832-a702-4401-bd79-f70b989ddd1e', ARRAY['buildout','module-21']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2130-0000-0000-0000-000000000009', 'What is the primary purpose of running cross (check) lines in a single-beam bathymetric survey?', 'multiple_choice', '["To increase vessel speed","To assess data quality by comparing depths where they intersect the main lines","To replace the need for a tide gauge","To measure sound velocity"]'::jsonb, 'To assess data quality by comparing depths where they intersect the main lines', 'Cross lines run perpendicular to main lines so depth agreement at intersections provides a quality check. They do not set speed, replace tides, or measure sound velocity.', 'medium', 'c1000015-0000-0000-0000-000000000015', '6ca85832-a702-4401-bd79-f70b989ddd1e', ARRAY['buildout','module-21']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2130-0000-0000-0000-000000000010', 'Why must lever-arm offsets between the GNSS antenna, transducer, and motion sensor be measured and applied?', 'multiple_choice', '["Because the sensors are rarely co-located, so soundings must be referred to the true transducer position","Because GNSS does not work over water","Because the chart datum changes hourly","Because side-scan needs them for imaging"]'::jsonb, 'Because the sensors are rarely co-located, so soundings must be referred to the true transducer position', 'The antenna, transducer, and motion sensor sit at different points on the vessel; their 3-D offsets plus attitude must be applied so each sounding refers to the actual transducer location and bottom point.', 'medium', 'c1000015-0000-0000-0000-000000000015', '6ca85832-a702-4401-bd79-f70b989ddd1e', ARRAY['buildout','module-21']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2130-0000-0000-0000-000000000011', 'Under Luttes v. State, what tidal datum bounds the seaward edge of a Spanish or Mexican coastal grant in Texas?', 'multiple_choice', '["Mean Lower Low Water (MLLW)","Mean High Water / Mean High Tide (MHW)","Mean Higher High Water (MHHW)","Mean Sea Level (MSL)"]'::jsonb, 'Mean Higher High Water (MHHW)', 'Luttes v. State (1959) holds that Spanish/Mexican grants are bounded by MHHW, reflecting civil-law definition of the shore by the highest tides. Texas-law grants use the MHW line.', 'medium', 'c1000015-0000-0000-0000-000000000015', '823b0a39-0438-4e0b-9544-e5782e6e7a8a', ARRAY['buildout','module-21']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2130-0000-0000-0000-000000000012', 'On a sloping shore, the MHHW line lies seaward of the MHW line.', 'true_false', '["True","False"]'::jsonb, 'False', 'MHHW is a higher datum than MHW, so on a sloping shore the MHHW contour lies LANDWARD of MHW, enlarging the State''s seabed for civil-law grants.', 'medium', 'c1000015-0000-0000-0000-000000000015', '823b0a39-0438-4e0b-9544-e5782e6e7a8a', ARRAY['buildout','module-21']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2130-0000-0000-0000-000000000013', 'A hurricane suddenly cuts a new channel and shifts the shoreline. How does this avulsive change affect the property boundary?', 'multiple_choice', '["The boundary moves with the new waterline","The boundary is fixed at its former location","Title passes to the State automatically","The boundary splits the difference"]'::jsonb, 'The boundary is fixed at its former location', 'Avulsion (sudden, perceptible change) fixes the boundary at its former location; title does not follow the water. Only gradual accretion/erosion moves the boundary.', 'medium', 'c1000015-0000-0000-0000-000000000015', '823b0a39-0438-4e0b-9544-e5782e6e7a8a', ARRAY['buildout','module-21']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2130-0000-0000-0000-000000000014', 'Before choosing the tidal datum for a Texas coastal boundary survey, what must the surveyor first establish?', 'short_answer', '[]'::jsonb, 'The original sovereign source of the grant (Spanish/Mexican vs. Anglo-American/Texas)', 'Because the datum is MHHW for Spanish/Mexican grants and MHW for Texas-law grants (Luttes), the surveyor must trace the chain of title back to the original sovereign before selecting the datum.', 'hard', 'c1000015-0000-0000-0000-000000000015', '823b0a39-0438-4e0b-9544-e5782e6e7a8a', ARRAY['buildout','module-21']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2130-0000-0000-0000-000000000015', 'Under the Texas statutory test, a stream is navigable if it retains an average width of how much, measured from its mouth up?', 'multiple_choice', '["10 feet","20 feet","30 feet","50 feet"]'::jsonb, '30 feet', 'Texas''s 30-foot rule (Nat. Res. Code Sec. 21.001(3)) makes a stream navigable if it averages 30 feet of bed width from its mouth up - measured across the entire bed, not the flowing water.', 'easy', 'c1000015-0000-0000-0000-000000000015', '52f79f9d-0221-4ca2-a4b0-8748463e791e', ARRAY['buildout','module-21']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2130-0000-0000-0000-000000000016', 'The 30-foot navigability measurement is taken on the width of water actually flowing on the day of the survey.', 'true_false', '["True","False"]'::jsonb, 'False', 'The 30 feet is measured across the entire bed (bank to bank), not the water flowing on a given day, so even a sometimes-dry channel can qualify as navigable.', 'medium', 'c1000015-0000-0000-0000-000000000015', '52f79f9d-0221-4ca2-a4b0-8748463e791e', ARRAY['buildout','module-21']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2130-0000-0000-0000-000000000017', 'What line forms the boundary between the State-owned bed and private upland along a navigable Texas stream?', 'multiple_choice', '["The ordinary high-water mark","The gradient boundary","The thread (center) of the stream","The mean lower low water line"]'::jsonb, 'The gradient boundary', 'Texas uses the distinctive gradient boundary (Motl v. Boyd; Oklahoma v. Texas), not the ordinary high-water mark. The center/thread applies to non-navigable streams; MLLW is a chart datum.', 'medium', 'c1000015-0000-0000-0000-000000000015', '52f79f9d-0221-4ca2-a4b0-8748463e791e', ARRAY['buildout','module-21']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2130-0000-0000-0000-000000000018', 'In Texas, owning the bank of a stream automatically gives the owner the right to appropriate the water for irrigation.', 'true_false', '["True","False"]'::jsonb, 'False', 'Texas surface water is State-owned; appropriative use requires a TCEQ permit under prior appropriation (Water Code Ch. 11). Bank ownership permits only limited domestic and livestock use.', 'medium', 'c1000015-0000-0000-0000-000000000015', '52f79f9d-0221-4ca2-a4b0-8748463e791e', ARRAY['buildout','module-21']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2130-0000-0000-0000-000000000019', 'Under the Texas Open Beaches Act, the public beach easement generally extends landward to which feature?', 'multiple_choice', '["The line of vegetation","The mean lower low water line","The seawall","The 30-foot line"]'::jsonb, 'The line of vegetation', 'TOBA protects a public easement over the dry beach to the line of vegetation. MLLW is a chart datum; the seawall and 30-foot line are unrelated to the beach easement.', 'easy', 'c1000015-0000-0000-0000-000000000015', '7829ced8-18ca-452d-9a24-dcf687354ea7', ARRAY['buildout','module-21']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2130-0000-0000-0000-000000000020', 'How did Severance v. Patterson (2012) limit the rolling beach easement?', 'multiple_choice', '["It abolished the public beach easement entirely","It held the easement migrates with gradual change but does not automatically roll onto previously private land after avulsion","It fixed the easement permanently at the 1959 shoreline","It extended the easement to mean lower low water"]'::jsonb, 'It held the easement migrates with gradual change but does not automatically roll onto previously private land after avulsion', 'Severance applied the gradual/avulsive distinction to the easement itself: it can roll with gradual shoreline change, but after an avulsive event the State must establish a new easement rather than roll onto previously private land.', 'hard', 'c1000015-0000-0000-0000-000000000015', '7829ced8-18ca-452d-9a24-dcf687354ea7', ARRAY['buildout','module-21']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2130-0000-0000-0000-000000000021', 'Which Texas agency issues permits to appropriate State-owned surface water?', 'multiple_choice', '["The General Land Office (GLO)","The Texas Commission on Environmental Quality (TCEQ)","The U.S. Army Corps of Engineers","The Railroad Commission"]'::jsonb, 'The Texas Commission on Environmental Quality (TCEQ)', 'TCEQ administers appropriative surface-water permits under prior appropriation (Water Code Ch. 11). The GLO manages submerged/public-trust lands and grant records; USACE handles federal navigable-waters permits.', 'medium', 'c1000015-0000-0000-0000-000000000015', '7829ced8-18ca-452d-9a24-dcf687354ea7', ARRAY['buildout','module-21']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
