INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2160-0000-0000-0000-000000000001', 'A draft-corrected raw sounding of {{raw:f2}} ft is recorded when the observed tide height is {{tide:f2}} ft above the chart datum. What is the reduced depth (ft) relative to the datum?', 'numeric_input', '[]'::jsonb, '0', 'Subtracting the tide height above datum ({{tide:f2}} ft) from the raw sounding ({{raw:f2}} ft) refers the depth to the chart datum: {{_answer}} ft.', 'easy', 'c1000015-0000-0000-0000-000000000015', NULL, ARRAY['buildout','module-21','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2150-0000-0000-0000-000000000001', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2160-0000-0000-0000-000000000002', 'At a tide station the Mean High Water datum is {{mhw:f2}} ft and the Mean Low Water datum is {{mlw:f2}} ft above chart datum. What is the mean tide range (ft)?', 'numeric_input', '[]'::jsonb, '0', 'The mean tide range is the vertical difference between the MHW and MLW datums: {{mhw:f2}} - {{mlw:f2}} = {{_answer}} ft.', 'easy', 'c1000015-0000-0000-0000-000000000015', NULL, ARRAY['buildout','module-21','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2150-0000-0000-0000-000000000002', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2160-0000-0000-0000-000000000003', 'A riparian tract has {{frontage:f1}} ft of water frontage. Over a period of years, gradual accretion adds an average width of {{accr:f1}} ft of new land along the entire frontage. What is the approximate area of accreted land (square feet)?', 'numeric_input', '[]'::jsonb, '0', 'Gradual accretion adds land to the upland owner. Treating the new land as a strip, area = frontage x average accretion width = {{frontage:f1}} x {{accr:f1}} = {{_answer}} sq ft.', 'medium', 'c1000015-0000-0000-0000-000000000015', NULL, ARRAY['buildout','module-21','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2150-0000-0000-0000-000000000003', 1);
